import{_ as a,o as i,c as s,a2 as r}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Persistencia","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/redis/04-persistencia.md","filePath":"bases-de-datos/redis/04-persistencia.md","lastUpdated":1782521464000}'),n={name:"bases-de-datos/redis/04-persistencia.md"};function o(t,e,l,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="persistencia" tabindex="-1">Persistencia <a class="header-anchor" href="#persistencia" aria-label="Permalink to &quot;Persistencia&quot;">​</a></h1><p>Redis vive principalmente en memoria, pero puede persistir datos en disco. La configuracion depende de cuanto dato puedes perder y que rendimiento necesitas.</p><h2 id="rdb" tabindex="-1">RDB <a class="header-anchor" href="#rdb" aria-label="Permalink to &quot;RDB&quot;">​</a></h2><p>RDB crea snapshots en momentos determinados.</p><p>Ventajas:</p><ul><li>Ficheros compactos.</li><li>Buen rendimiento.</li><li>Restauracion rapida.</li></ul><p>Riesgo:</p><ul><li>Puedes perder cambios desde el ultimo snapshot.</li></ul><p>Ejemplo de idea:</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>save 900 1</span></span>
<span class="line"><span>save 300 10</span></span>
<span class="line"><span>save 60 10000</span></span></code></pre></div><h2 id="aof" tabindex="-1">AOF <a class="header-anchor" href="#aof" aria-label="Permalink to &quot;AOF&quot;">​</a></h2><p>Append Only File registra operaciones de escritura.</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>appendonly yes</span></span>
<span class="line"><span>appendfsync everysec</span></span></code></pre></div><p>Opciones:</p><ul><li><code>always</code>: mas seguro, mas lento.</li><li><code>everysec</code>: equilibrio habitual.</li><li><code>no</code>: depende del sistema operativo.</li></ul><h2 id="rdb-aof" tabindex="-1">RDB + AOF <a class="header-anchor" href="#rdb-aof" aria-label="Permalink to &quot;RDB + AOF&quot;">​</a></h2><p>Muchas instalaciones combinan ambas estrategias: RDB para snapshots y AOF para reducir perdida de datos.</p><h2 id="restauracion" tabindex="-1">Restauracion <a class="header-anchor" href="#restauracion" aria-label="Permalink to &quot;Restauracion&quot;">​</a></h2><p>Antes de restaurar:</p><ul><li>Comprueba version de Redis.</li><li>Copia archivos originales.</li><li>Arranca en entorno separado si puedes.</li><li>Verifica claves criticas.</li></ul><h2 id="que-estrategia-elegir" tabindex="-1">Que estrategia elegir <a class="header-anchor" href="#que-estrategia-elegir" aria-label="Permalink to &quot;Que estrategia elegir&quot;">​</a></h2><ul><li>Cache pura: puede no necesitar persistencia.</li><li>Sesiones: depende del impacto de perderlas.</li><li>Cola/eventos: AOF suele ser mas importante.</li><li>Datos criticos: evalua si Redis es el sistema adecuado.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Define RPO: cuanto dato puedes perder.</li><li>Monitoriza uso de disco.</li><li>Prueba restauraciones.</li><li>No confundas replica con backup.</li><li>Documenta configuracion de persistencia.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Creer que Redis siempre persiste.</li><li>Activar AOF sin vigilar disco.</li><li>No probar restore.</li><li>Usar Redis como unica fuente de verdad sin estrategia.</li><li>Copiar archivos mientras Redis escribe sin procedimiento claro.</li></ul>`,26)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
